    POSVECTYPE* position = (POSVECTYPE*) malloc(nAtom * sizeof(POSVECTYPE));
    FORCEVECTYPE* force = (FORCEVECTYPE*) malloc(nAtom * sizeof(FORCEVECTYPE));
    int *neighborList = (int*) malloc(maxNeighbors * nAtom * sizeof(int));

    std::cout << "Initializing test problem (this can take several minutes for large problems).\n";

    srand(123);

    for (int i = 0; i < nAtom; i++)
    {
        position[i].x = rand() % domainEdge;
        position[i].y = rand() % domainEdge;
        position[i].z = rand() % domainEdge;
    }

    std::cout << "Finished.\n";
    int totalPairs = buildNeighborList<FPTYPE, POSVECTYPE>(nAtom, position, neighborList);
    std::cout << totalPairs << " of " << nAtom*maxNeighbors
              << " pairs within cutoff distance = "
              << 100.0 * ((double)totalPairs / (nAtom*maxNeighbors)) << " %\n";

    // Allocate GPU memory
    POSVECTYPE* d_position;
    FORCEVECTYPE* d_force;
    int* d_neighborList;

    cudaMalloc(&d_position, nAtom * sizeof(POSVECTYPE));
    cudaMalloc(&d_force, nAtom * sizeof(FORCEVECTYPE));
    cudaMalloc(&d_neighborList, maxNeighbors * nAtom * sizeof(int));

    // Copy data to GPU
    cudaMemcpy(d_position, position, nAtom * sizeof(POSVECTYPE), cudaMemcpyHostToDevice);
    cudaMemcpy(d_neighborList, neighborList, maxNeighbors * nAtom * sizeof(int), cudaMemcpyHostToDevice);

    // Configure kernel launch parameters (thread_limit(256) from OpenMP)
    int blockSize = 256;
    int numBlocks = (nAtom + blockSize - 1) / blockSize;

    // Initial kernel call for correctness check
    md_kernel(numBlocks, blockSize,
              d_position,
              d_force,
              d_neighborList,
              nAtom,
              maxNeighbors,
              lj1,
              lj2,
              cutsq);

    // Copy results back to host for correctness check
    cudaMemcpy(force, d_force, nAtom * sizeof(FORCEVECTYPE), cudaMemcpyDeviceToHost);

    std::cout << "Performing Correctness Check (may take several minutes)\n";

    checkResults<FPTYPE, FORCEVECTYPE, POSVECTYPE>(force, position, neighborList, nAtom);

    auto start = std::chrono::steady_clock::now();

    for (int i = 0; i < iteration; i++) {
        md_kernel(numBlocks, blockSize,
                  d_position,
                  d_force,
                  d_neighborList,
                  nAtom,
                  maxNeighbors,
                  lj1,
                  lj2,
                  cutsq);
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average kernel execution time " << (time * 1e-9f) / iteration << " (s)\n";

    // Free GPU memory
    cudaFree(d_position);
    cudaFree(d_force);
    cudaFree(d_neighborList);

    free(position);
    free(force);
    free(neighborList);

    return 0;
}

