#include <cassert>
#include <chrono>
#include <cfloat>
#include <cmath>
#include <cstdlib>
#include <list>
#include <iostream>
#include "MD.h"
#include "reference.h"
#include "utils.h"

__global__ void md_kernel(
    const POSVECTYPE* __restrict position,
    FORCEVECTYPE* __restrict force,
    const int* __restrict neighborList, 
    const int nAtom,
    const int maxNeighbors, 
    const FPTYPE lj1_t,
    const FPTYPE lj2_t,
    const FPTYPE cutsq_t )
{
    uint idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx < nAtom) {
        POSVECTYPE ipos = position[idx];
        FORCEVECTYPE f = zero;

        int j = 0;
        while (j < maxNeighbors)
        {
            int jidx = neighborList[j*nAtom + idx];

            POSVECTYPE jpos = position[jidx];

            FPTYPE delx = ipos.x - jpos.x;
            FPTYPE dely = ipos.y - jpos.y;
            FPTYPE delz = ipos.z - jpos.z;
            FPTYPE r2inv = delx*delx + dely*dely + delz*delz;

            if (r2inv > 0 && r2inv < cutsq_t)
            {
                r2inv = (FPTYPE)1.0 / r2inv;
                FPTYPE r6inv = r2inv * r2inv * r2inv;
                FPTYPE forceC = r2inv*r6inv*(lj1_t*r6inv - lj2_t);

                f.x += delx * forceC;
                f.y += dely * forceC;
                f.z += delz * forceC;
            }
            j++;
        }
        force[idx] = f;
    }
}

void md(
    const POSVECTYPE* __restrict position,
    FORCEVECTYPE* __restrict force,
    const int* __restrict neighborList, 
    const int nAtom,
    const int maxNeighbors, 
    const FPTYPE lj1_t,
    const FPTYPE lj2_t,
    const FPTYPE cutsq_t )
{
    int threadsPerBlock = 256;
    int blocksPerGrid = (nAtom + threadsPerBlock - 1) / threadsPerBlock;

    md_kernel<<<blocksPerGrid, threadsPerBlock>>>(
        position, force, neighborList, nAtom, maxNeighbors,
        lj1_t, lj2_t, cutsq_t);
}

