    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_tiled_kernel<T, 64><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  128: {conv1d_tiled_kernel<T, 128><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  256: {conv1d_tiled_kernel<T, 256><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  512: {conv1d_tiled_kernel<T, 512><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
