template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = memcmp(ref_out, out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (ref_out[i] != out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
__global__ void scanKernelWithBankConflicts(T* in, T* out, int64_t num_blocks)
{
  T temp[N];
  int thid = threadIdx.x;
  int64_t bid = blockIdx.x;

  if (bid < num_blocks) {
    T* t_in  = in + bid * N;
    T* t_out = out + bid * N;

    temp[2*thid]   = t_in[2*thid];
    temp[2*thid+1] = t_in[2*thid+1];

    int offset = 1;
    for (int d = N >> 1; d > 0; d >>= 1)
    {
      __syncthreads();
      if (thid < d)
      {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        temp[bi] += temp[ai];
      }
      offset *= 2;
    }

    if (thid == 0) temp[N-1] = 0;
    for (int d = 1; d < N; d *= 2)
    {
      offset >>= 1;
      __syncthreads();
      if (thid < d)
      {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }
    t_out[2*thid] = temp[2*thid];
    t_out[2*thid+1] = temp[2*thid+1];
  }
}

template<typename T, int N>
__global__ void scanKernelWithoutBankConflicts(T* in, T* out, int64_t num_blocks)
{
  T temp[2*N];
  int thid = threadIdx.x;
  int64_t bid = blockIdx.x;

  if (bid < num_blocks) {
    T* t_in  = in + bid * N;
    T* t_out = out + bid * N;

    int a = thid;
    int b = a + (N/2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);

    temp[a + oa] = t_in[a];
    temp[b + ob] = t_in[b];

    int offset = 1;
    for (int d = N >> 1; d > 0; d >>= 1)
    {
      __syncthreads();
      if (thid < d)
      {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        ai += OFFSET(ai);
        bi += OFFSET(bi);
        temp[bi] += temp[ai];
      }
      offset *= 2;
    }

    if (thid == 0) temp[N-1+OFFSET(N-1)] = 0;
    for (int d = 1; d < N; d *= 2)
    {
      offset >>= 1;
      __syncthreads();
      if (thid < d)
      {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        ai += OFFSET(ai);
        bi += OFFSET(bi);
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }
    __syncthreads();

    t_out[a] = temp[a + oa];
    t_out[b] = temp[b + ob];
  }
}

template<typename T, int N>
void runTest(const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N;
  int64_t bytes = nelems * sizeof(T);

  T* in = (T*)malloc(bytes);
  T* out = (T*)malloc(bytes);
  T* ref_out = (T*)malloc(bytes);

  T* d_in;
  T* d_out;
  cudaMalloc(&d_in, bytes);
  cudaMalloc(&d_out, bytes);

  srand(123);
  for (int64_t i = 0; i < nelems; i++) in[i] = rand() % 5 + 1;

  T* t_in = in;
  T* t_out = ref_out;
  for (int64_t i = 0; i < num_blocks; i++) {
    t_out[0] = 0;
    for (int j = 1; j < N; j++)
      t_out[j] = t_out[j-1] + t_in[j-1];
    t_out += N;
    t_in += N;
  }

  cudaMemcpy(d_in, in, bytes, cudaMemcpyHostToDevice);

  cudaEvent_t start, end;
  cudaEventCreate(&start);
  cudaEventCreate(&end);

  cudaEventRecord(start);
  for (int i = 0; i < repeat; i++) {
    scanKernelWithBankConflicts<T, N><<<num_blocks, N/2>>>(d_in, d_out, num_blocks);
  }
  cudaEventRecord(end);
  cudaEventSynchronize(end);

  float time_ms;
  cudaEventElapsedTime(&time_ms, start, end);
  long long time_ns = (long long)(time_ms * 1e6);

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time_ns * 1e-3f) / repeat);
  }

  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out, out, nelems);

  cudaEventRecord(start);
  for (int i = 0; i < repeat; i++) {
    scanKernelWithoutBankConflicts<T, N><<<num_blocks, N/2>>>(d_in, d_out, num_blocks);
  }
  cudaEventRecord(end);
  cudaEventSynchronize(end);

  cudaEventElapsedTime(&time_ms, start, end);
  long long bcao_time_ns = (long long)(time_ms * 1e6);

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time_ns * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time_ns - bcao_time_ns) * 1.0 / time_ns * 100);
  }

  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out, out, nelems);

  cudaFree(d_in);
  cudaFree(d_out);
  cudaEventDestroy(start);
  cudaEventDestroy(end);

  free(in);
  free(out);
  free(ref_out);
}

template<int N>
void run(const int n, const int repeat) {
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest<char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<int, N>(n, repeat, report_timing);
    runTest<long, N>(n, repeat, report_timing);
  }
}

